func (s *OrderServiceServer) CreateOrder(ctx context.Context, req *orderpb.CreateOrderRequest) (*orderpb.Order, error) {
	if err := validateAuthToken(ctx); err != nil {
		return nil, err
	}

	if req.GetUserId() == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.GetItems()) == 0 {
		return nil, status.Error(codes.InvalidArgument, "at least one item is required")
	}
	if len(req.GetItems()) > 100 {
		return nil, status.Error(codes.InvalidArgument, "too many items in order")
	}

	var totalAmount float64
	for _, item := range req.GetItems() {
		if item.GetQuantity() <= 0 {
			return nil, status.Error(codes.InvalidArgument, "item quantity must be positive")
		}
		if item.GetPrice() < 0 {
			return nil, status.Error(codes.InvalidArgument, "item price cannot be negative")
		}
		if item.GetProductId() == "" {
			return nil, status.Error(codes.InvalidArgument, "product_id is required for each item")
		}
		totalAmount += item.GetPrice() * float64(item.GetQuantity())
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	orderID := generateID("order")
	order := &orderpb.Order{
		Id:          orderID,
		UserId:      req.GetUserId(),
		Items:       req.GetItems(),
		TotalAmount: totalAmount,
		Status:      orderpb.OrderStatus_ORDER_STATUS_PENDING,
		CreatedAt:   timestamppb.Now(),
		UpdatedAt:   timestamppb.Now(),
	}
	s.orders[orderID] = order

	log.Printf("Order created: %s for user: %s", orderID, req.GetUserId())
	return order, nil
}

