// --- Helper Functions ---

func validateAuthToken(ctx context.Context) error {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return status.Error(codes.Unauthenticated, "missing metadata")
	}

	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return status.Error(codes.Unauthenticated, "missing authorization token")
	}

	token := authHeaders[0]
	if len(token) < 7 || token[:7] != "Bearer " {
		return status.Error(codes.Unauthenticated, "invalid authorization format")
	}

	tokenValue := token[7:]
	if tokenValue == "" {
		return status.Error(codes.Unauthenticated, "empty token")
	}

	// In production, validate JWT token here
	// For development, accept any non-empty bearer token
	return nil
}

var (
	idCounter int64
	idMu      sync.Mutex
)

func generateID(prefix string) string {
	idMu.Lock()
	defer idMu.Unlock()
	idCounter++
	return fmt.Sprintf("%s_%d_%d", prefix, time.Now().UnixNano(), idCounter)
}

func isValidStatusTransition(from, to orderpb.OrderStatus) bool {
	validTransitions := map[orderpb.OrderStatus][]orderpb.OrderStatus{
		orderpb.OrderStatus_ORDER_STATUS_PENDING: {
			orderpb.OrderStatus_ORDER_STATUS_CONFIRMED,
			orderpb.OrderStatus_ORDER_STATUS_CANCELLED,
		},
		orderpb.OrderStatus_ORDER_STATUS_CONFIRMED: {
			orderpb.OrderStatus_ORDER_STATUS_SHIPPED,
			orderpb.OrderStatus_ORDER_STATUS_CANCELLED,
		},
		orderpb.OrderStatus_ORDER_STATUS_SHIPPED: {
			orderpb.OrderStatus_ORDER_STATUS_DELIVERED,
		},
	}

	allowed, ok := validTransitions[from]
	if !ok {
		return false
	}
	for _, s := range allowed {
		if s == to {
			return true
		}
	}
	return false
}

// --- Interceptors ---

func unaryLoggingInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	start := time.Now()
	resp, err := handler(ctx, req)
	duration := time.Since(start)

	statusCode := codes.OK
	if err != nil {
		if st, ok := status.FromError(err); ok {
			statusCode = st.Code()
		}
	}

	log.Printf("gRPC call: method=%s duration=%v status=%s", info.FullMethod, duration, statusCode)
	return resp, err
}

func unaryRecoveryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("Recovered from panic in %s: %v", info.FullMethod, r)
			err = status.Errorf(codes.Internal, "internal server error")
		}
	}()
	return handler(ctx, req)
}

func chainUnaryInterceptors(interceptors ...grpc.UnaryServerInterceptor) grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		chain := handler
		for i := len(interceptors) - 1; i >= 0; i-- {
			interceptor := interceptors[i]
			next := chain
			chain = func(ctx context.Context, req interface{}) (interface{}, error) {
				return interceptor(ctx, req, info, func(ctx context.Context, req interface{}) (interface{}, error) {
					return next(ctx, req)
				})
			}
		}
		return chain(ctx, req)
	}
}

// --- TLS Configuration ---

func loadTLSCredentials() (credentials.TransportCredentials, error) {
	certFile := getEnvOrDefault("TLS_CERT_FILE", "certs/server-cert.pem")
	keyFile := getEnvOrDefault("TLS_KEY_FILE", "certs/server-key.pem")
	caFile := getEnvOrDefault("TLS_CA_FILE", "certs/ca-cert.pem")

	serverCert, err := tls.LoadX509KeyPair(certFile, keyFile)
	if err != nil {
		return nil, fmt.Errorf("failed to load server certificate: %w", err)
	}

	caCert, err := os.ReadFile(caFile)
	if err != nil {
		return nil, fmt.Errorf("failed to read CA certificate: %w", err)
	}

	certPool := x509.NewCertPool()
	if !certPool.AppendCertsFromPEM(caCert) {
		return nil, fmt.Errorf("failed to add CA certificate to pool")
	}

	config := &tls.Config{
		Certificates: []tls.Certificate{serverCert},
		ClientAuth:   tls.RequireAndVerifyClientCert,
		ClientCAs:    certPool,
		MinVersion:   tls.VersionTLS13,
	}

	return credentials.NewTLS(config), nil
}

func getEnvOrDefault(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

func isDevelopment() bool {
	env := os.Getenv("ENVIRONMENT")
	return env == "" || env == "development" || env == "dev"
}

// --- Main ---

func main() {
	port := getEnvOrDefault("GRPC_PORT", "50051")

	var serverOpts []grpc.ServerOption

	// TLS configuration
	if !isDevelopment() || os.Getenv("ENABLE_TLS") == "true" {
		tlsCreds, err := loadTLSCredentials()
		if err != nil {
			log.Fatalf("Failed to load TLS credentials: %v", err)
		}
		serverOpts = append(serverOpts, grpc.Creds(tlsCreds))
		log.Println("TLS enabled")
	} else {
		log.Println("WARNING: Running without TLS (development mode)")
	}

	// Add interceptors
	combinedInterceptor := chainUnaryInterceptors(
		unaryRecoveryInterceptor,
		unaryLoggingInterceptor,
	)
	serverOpts = append(serverOpts,
		grpc.UnaryInterceptor(combinedInterceptor),
		grpc.MaxRecvMsgSize(4*1024*1024),   // 4MB max receive
		grpc.MaxSendMsgSize(4*1024*1024),   // 4MB max send
		grpc.MaxConcurrentStreams(100),
	)

	grpcServer := grpc.NewServer(serverOpts...)

	// Register services
	userService := NewUserServiceServer()
	orderService := NewOrderServiceServer()
	paymentService := NewPaymentServiceServer()

	userpb.RegisterUserServiceServer(grpcServer, userService)
	orderpb.RegisterOrderServiceServer(grpcServer, orderService)
	paymentpb.RegisterPaymentServiceServer(grpcServer, paymentService)

	// Enable reflection only in development/testing environments
	if isDevelopment() {
		reflection.Register(grpcServer)
		log.Println("gRPC reflection enabled (development mode)")
	}

	listener, err := net.Listen("tcp", ":"+port)
	if err != nil {
		log.Fatalf("Failed to listen on port %s: %v", port, err)
	}

	// Graceful shutdown
	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		sig := <-sigChan
		log.Printf("Received signal %v, initiating graceful shutdown...", sig)
		grpcServer.GracefulStop()
	}()

	log.Printf("gRPC server starting on port %s", port)
	log.Printf("Services registered: UserService, OrderService, PaymentService")

	if err := grpcServer.Serve(listener); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}

	log.Println("Server stopped")
}